import { Navigate, Route, Routes } from 'react-router-dom';
import HomePage from '../Pages/HomePage';
import ProductsPage from '../Pages/ProductsPage';
import CartPage from '../Pages/CartPage';
import AboutPage from '../Pages/AboutPage';
import ContactPage from '../Pages/ContactPage';
import FaqPage from '../Pages/FaqPage';
import ForgotPasswordPage from '../Pages/ForgotPasswordPage';
import LoginPage from '../Pages/LoginPage';
import SignupPage from '../Pages/SignupPage';
import PrivacyPage from '../Pages/PrivacyPage';
import TermsPage from '../Pages/TermsPage';
import NotFoundPage from '../Pages/NotFoundPage';

// Customer Pages
import ProductDetails from '../Pages/ProductDetails';
import Wishlist from '../Pages/Wishlist';
import Checkout from '../Pages/Checkout';
import OrderSuccess from '../Pages/OrderSuccess';
import MyOrders from '../Pages/MyOrders';
import Profile from '../Pages/Profile';
import SizeGuide from '../Pages/SizeGuide';
import Offers from '../Pages/Offers';

// Admin Pages and Layout
import AdminLayout from '../Components/AdminLayout';
import AdminDashboard from '../Pages/AdminDashboard';
import AdminProducts from '../Pages/AdminProducts';
import AdminOrders from '../Pages/AdminOrders';
import AdminUsers from '../Pages/AdminUsers';
import AdminOffers from '../Pages/AdminOffers';

import { useStore } from '../Components/StoreContext';

// Protected Route for Authenticated Users (Redirects Admin to Admin Dashboard)
const ProtectedRoute = ({ children }) => {
  const { currentUser } = useStore();
  if (!currentUser) return <Navigate replace to="/login" />;
  if (currentUser.role === 'admin') return <Navigate replace to="/admin/dashboard" />;
  return children;
};

// Admin Protection Route
const AdminRoute = ({ children }) => {
  const { currentUser } = useStore();
  return currentUser && currentUser.role === 'admin' ? children : <Navigate replace to="/" />;
};

// Guest Only Route (Prevent logged-in users from accessing Login/Signup)
const GuestRoute = ({ children }) => {
  const { currentUser } = useStore();
  if (currentUser) {
    return <Navigate replace to={currentUser.role === 'admin' ? '/admin/dashboard' : '/'} />;
  }
  return children;
};

const AppRoutes = () => (
  <Routes>
    {/* Public Routes */}
    <Route path="/login" element={<GuestRoute><LoginPage /></GuestRoute>} />
    <Route path="/signup" element={<GuestRoute><SignupPage /></GuestRoute>} />
    <Route path="/forgot-password" element={<GuestRoute><ForgotPasswordPage /></GuestRoute>} />
    <Route path="/about" element={<AboutPage />} />
    <Route path="/contact" element={<ContactPage />} />
    <Route path="/faq" element={<FaqPage />} />
    <Route path="/privacy" element={<PrivacyPage />} />
    <Route path="/terms" element={<TermsPage />} />

    {/* Protected Customer Routes */}
    <Route path="/" element={<ProtectedRoute><HomePage /></ProtectedRoute>} />
    <Route path="/index.html" element={<Navigate replace to="/" />} />
    <Route path="/products" element={<ProtectedRoute><ProductsPage /></ProtectedRoute>} />
    <Route path="/cart" element={<ProtectedRoute><CartPage /></ProtectedRoute>} />
    <Route path="/product/:id" element={<ProtectedRoute><ProductDetails /></ProtectedRoute>} />
    <Route path="/wishlist" element={<ProtectedRoute><Wishlist /></ProtectedRoute>} />
    <Route path="/checkout" element={<ProtectedRoute><Checkout /></ProtectedRoute>} />
    <Route path="/order-success" element={<ProtectedRoute><OrderSuccess /></ProtectedRoute>} />
    <Route path="/my-orders" element={<ProtectedRoute><MyOrders /></ProtectedRoute>} />
    <Route path="/profile" element={<ProtectedRoute><Profile /></ProtectedRoute>} />
    <Route path="/size-guide" element={<ProtectedRoute><SizeGuide /></ProtectedRoute>} />
    <Route path="/offers" element={<ProtectedRoute><Offers /></ProtectedRoute>} />

    {/* Protected Admin Nested Routes */}
    <Route 
      path="/admin" 
      element={
        <AdminRoute>
          <AdminLayout />
        </AdminRoute>
      }
    >
      <Route index element={<Navigate replace to="dashboard" />} />
      <Route path="dashboard" element={<AdminDashboard />} />
      <Route path="products" element={<AdminProducts />} />
      <Route path="orders" element={<AdminOrders />} />
      <Route path="users" element={<AdminUsers />} />
      <Route path="offers" element={<AdminOffers />} />
    </Route>

    <Route path="*" element={<NotFoundPage />} />
  </Routes>
);

export default AppRoutes;
